const LOKI_URL = process.env.LOKI_URL || 'http://loki.galaxy:3100';
const query = $parameter.query;
const since = $parameter.since || '30m';
const limit = $parameter.limit || 50;

const params = new URLSearchParams({
  query,
  since,
  limit: String(limit),
  direction: 'backward'
});

const response = await $helpers.httpRequest({
  method: 'GET',
  url: `${LOKI_URL}/loki/api/v1/query_range?${params}`,
  headers: { 'Content-Type': 'application/json' }
});

const streams = response?.data?.result || [];
if (streams.length === 0) return 'No logs found for query: ' + query;

const lines = streams.flatMap(s => s.values.map(v => v[1])).slice(0, limit);
return `Found ${lines.length} log lines:\n` + lines.join('\n');

const body = $input.first().json.body || $input.first().json;

// Handle both Grafana unified alerting and legacy formats
const alerts = body.alerts || [];
const status = body.status || 'firing';

if (alerts.length === 0) {
  return [{ json: { skip: true, reason: 'No alerts in payload' } }];
}

const results = [];
for (const alert of alerts) {
  const alertName = alert.labels?.alertname || 'Unknown Alert';
  const severity = alert.labels?.severity || 'unknown';
  const host = (alert.labels?.instance || alert.labels?.host || 'unknown').replace(/:\d+$/, '');
  const summary = alert.annotations?.summary || alert.annotations?.description || '';
  const state = alert.status || status;
  const startsAt = alert.startsAt || new Date().toISOString();

  // Build a clear prompt for NOLA
  const triagePrompt = `A Grafana alert has fired. Please triage it.

**Alert:** ${alertName}
**Status:** ${state}
**Severity:** ${severity}
**Host:** ${host}
**Summary:** ${summary}
**Fired at:** ${startsAt}

Please query Loki for relevant context (use a 30m window around the alert time on the relevant host), analyze what's happening, and post your triage verdict to Discord using post_to_discord.`;

  results.push({
    json: {
      alertName,
      severity,
      host,
      summary,
      state,
      startsAt,
      triagePrompt,
      skip: false
    }
  });
}

return results;

const WEBHOOK_URL = process.env.DISCORD_WEBHOOK_URL;
if (!WEBHOOK_URL) return 'Discord webhook URL not configured';

const message = $parameter.message;
const response = await $helpers.httpRequest({
  method: 'POST',
  url: WEBHOOK_URL,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ content: message })
});
return `Posted to Discord (status: ${response.statusCode || 'ok'})`;
